spec.expr:
{source="fluent_bit", job="kube_events", cluster=~"$cluster"} 
  | json  
  | line_format `{{if eq .type "Normal"}}✅{{else}}⚠️{{end}} | 📦 Object: {{.involvedObject_kind}}/{{.involvedObject_name}} ({{.involvedObject_namespace}}) -> {{.reason}} | 🛠️ Source: {{.source_component}} {{if ne .source_host ""}}🌐 Host: {{.source_host}} {{end}}
📝 Message: {{.message | trim}}`

sum by(source) (
  count_over_time(
    {source="fluent_bit", job="kube_events", cluster=~"$cluster"} 
    | json
    | type="Normal" 
    [$__range]
  ) > 0
)
